 1	import type { FC, ReactNode } from 'react';
 2	import useToggle from 'src/modules/Providers/hooks/useToggle';
 3	
 4	import SectionHeading from '@components/headers/SectionHeading';
 5	import { Button, ButtonVariant, Flex, FlexItem, Icon, Tooltip } from '@patternfly/react-core';
 6	import { AngleDownIcon, AngleRightIcon, HelpIcon } from '@patternfly/react-icons';
 7	
 8	import './ExpandableSectionHeading.scss';
 9	
10	type ExpandableSectionHeadingProps = {
11	  section: ReactNode;
12	  sectionTitle: ReactNode;
13	  sectionHelpTip?: ReactNode;
14	  initialExpanded?: boolean;
15	};
16	
17	const ExpandableSectionHeading: FC<ExpandableSectionHeadingProps> = ({
18	  initialExpanded = false,
19	  section,
20	  sectionHelpTip,
21	  sectionTitle,
22	}) => {
23	  const [showSection, setShowSection] = useToggle(initialExpanded);
24	  return (
25	    <>
26	      <Flex alignItems={{ default: 'alignItemsCenter' }} gap={{ default: 'gapSm' }}>
27	        <FlexItem>
28	          <Button
29	            className="expandable-section-heading"
30	            isInline
31	            variant={ButtonVariant.plain}
32	            onClick={setShowSection}
33	          >
34	            <SectionHeading
35	              text={
36	                <Flex
37	                  className="expandable-section-heading__title"
38	                  alignItems={{ default: 'alignItemsCenter' }}
39	                  gap={{ default: 'gapSm' }}
40	                >
41	                  <FlexItem>{showSection ? <AngleDownIcon /> : <AngleRightIcon />}</FlexItem>
42	                  <FlexItem>{sectionTitle}</FlexItem>
43	                </Flex>
44	              }
45	            />
46	          </Button>
47	        </FlexItem>
48	        {sectionHelpTip ? (
49	          <FlexItem>
50	            <Tooltip content={sectionHelpTip}>
51	              <Icon size="md">
52	                <HelpIcon />
53	              </Icon>
54	            </Tooltip>
55	          </FlexItem>
56	        ) : null}
57	      </Flex>
58	      {showSection && section}
59	    </>
60	  );
61	};
62	
63	export default ExpandableSectionHeading;

